#!/usr/bin/env python3
"""Apply 17 trading-journal bug fixes. Run: python3 apply-fixes.py"""
import base64, os, sys

BASE = "/var/www/trading-journal"

FILES = {
    'frontend/src/components/AppShell.tsx': '',
    'frontend/src/components/WalletModal.tsx': '',
    'frontend/src/components/ui.tsx': '',
    'frontend/src/components/editor/ImageDrop.tsx': '',
    'frontend/src/components/editor/tabs/EssentialsTab.tsx': '',
    'frontend/src/components/editor/tabs/ManagementTab.tsx': '',
    'frontend/src/components/editor/tabs/ChecklistTab.tsx': '',
    'frontend/src/components/editor/tabs/TagsTab.tsx': '',
    'frontend/src/app/journals/page.tsx': '',
    'frontend/src/app/journals/[id]/page.tsx': '',
    'frontend/src/app/admin/users/[id]/page.tsx': '',
    'frontend/src/app/dashboard/page.tsx': '',
}

def main():
    print(f"Applying fixes to {BASE} ...")
    for rel, b64 in FILES.items():
        full = os.path.join(BASE, rel)
        os.makedirs(os.path.dirname(full), exist_ok=True)
        with open(full, "wb") as f:
            f.write(base64.b64decode(b64))
        print(f"  + {rel}")
    print("\nAll 12 files applied.")
    print("Next: cd /var/www/trading-journal/frontend && npm run build && pm2 restart tj-frontend")

if __name__ == "__main__":
    main()